import{_ as e,c as t,a0 as s,o as i}from"./chunks/framework.CoDf8mVe.js";const r="/assets/ll01.B-DGrSZE.png",u=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/guide/getting-started.md","filePath":"zh-CN/guide/getting-started.md","lastUpdated":1726535142000}'),l={name:"zh-CN/guide/getting-started.md"};function n(p,a,o,h,d,c){return i(),t("div",null,a[0]||(a[0]=[s('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>NapCatQQ V2 正式开始测试，欢迎来到 NapCatQQ (aka 猫猫框架) 的使用文档！</p><h2 id="使用之前" tabindex="-1">使用之前 <a class="header-anchor" href="#使用之前" aria-label="Permalink to &quot;使用之前&quot;">​</a></h2><p>在开始使用之前，你需要了解以下内容。</p><details class="details custom-block"><summary>猫猫框架的原理是什么，能够做些什么？</summary><p>猫猫框架通过魔法的手段获得了 QQ 的发送消息、接收消息等接口，为了方便使用，猫猫框架将通过一种名为 <a href="https://11.onebot.dev" target="_blank" rel="noreferrer">OneBot</a> 的约定将你的 HTTP / WebSocket 请求按照规范读取，再去调用猫猫框架所获得的QQ发送接口之类的接口。</p></details><h2 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h2><p>前往 <a href="https://github.com/NapNeko/NapCatQQ/releases" target="_blank" rel="noreferrer">NapCatQQ 的 release 页面</a>，各位可以看到有两个压缩包， 文件名后缀分别为 <code>Shell</code> 和 <code>Framework</code>，应当如何选择呢？ 这就需要了解猫猫框架的启动方式了。</p><ol><li><p><a href="#方法1-作为-liteloader-插件启动">方法 1</a> 作为 <a href="https://liteloaderqqnt.github.io/" target="_blank" rel="noreferrer">LiteLoaderQQNT</a> 插件运行，类似 <a href="https://llonebot.github.io" target="_blank" rel="noreferrer">LLOneBot</a>，可以实现“人机合一”。</p></li><li><p><a href="#方法2-通过命令行启动">方法 2</a> 通过命令行启动，当你不需要或没有图形化界面，或者内存紧张，可以使用此方法。</p></li><li><p><a href="#方法3-only-gui">方法 3</a> “Only GUI” 模式，当你不想使用 LiteLoader 插件时，却又想人机合一，又想折腾时，可以考虑此方法。</p></li></ol><p>方法 1 和 3 都是“有头启动”，应当使用 Framework 版本；方法 2 是无头启动，应当使用 Shell 版本。我们目前对方法 1 和 2 有较为完整的文档支持，方法 3 还请自行探索。</p><h3 id="方法1-作为-liteloader-插件启动" tabindex="-1">方法1: 作为 LiteLoader 插件启动 <a class="header-anchor" href="#方法1-作为-liteloader-插件启动" aria-label="Permalink to &quot;方法1: 作为 LiteLoader 插件启动&quot;">​</a></h3><p>** 此方法可能不再适用于2.5.4+版本 需要LiteLoader兼容 如果需要使用可以尝试2.5.4+ 失败请使用2.5.4以下版本 **</p><ol><li><p>按照 <a href="https://liteloaderqqnt.github.io/" target="_blank" rel="noreferrer">LiteLoaderQQNT 官网</a> 的指导安装 LiteLoaderQQNT 框架。</p></li><li><p>在 LiteLoaderQQNT 的设置页面（如下图）将 <code>NapCat.Framework.zip</code> 导入即可。 <img src="'+r+'" alt="在这里"></p></li></ol><h3 id="方法2-通过命令行启动" tabindex="-1">方法2: 通过命令行启动 <a class="header-anchor" href="#方法2-通过命令行启动" aria-label="Permalink to &quot;方法2: 通过命令行启动&quot;">​</a></h3><h4 id="一键撸猫" tabindex="-1">一键撸猫 <a class="header-anchor" href="#一键撸猫" aria-label="Permalink to &quot;一键撸猫&quot;">​</a></h4><details class="details custom-block"><summary>Windows X64 自动化安装程序</summary><p><a href="https://github.com/NapNeko/NapCat-Win-Installer/releases/tag/v1.0.0" target="_blank" rel="noreferrer">前往下载</a></p><p>复制到你需要的目录双击启动程序 即可 如果存在问题 请前往官方群和issue反馈 并尝试下面的方案</p><p>安装完成 双击目录下launcher.bat即可启动 如果是win10 则使用launcher-win10.bat</p><p>修改配置见本文最后 NapCat 的基础设置 同时 你可以也可以使用 图形化WebUi远程配置</p><p>注意 如果需要快速登录 命令行执行 或者 新建bat</p><p>Win11: <code>.\\launcher.bat 123456</code></p><p>Win 10: <code>.\\launcher-win10.bat 123456</code></p></details><details class="details custom-block"><summary>Linux 一键脚本 (适用于 Ubuntu <strong>20+</strong> / Debian <strong>10+</strong> / CentOS <strong>9</strong>)</summary><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> napcat.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://nclatest.znin.net/NapNeko/NapCat-Installer/main/script/install.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> napcat.sh</span></span></code></pre></div></details><details class="details custom-block"><summary>Linux 下使用 Docker</summary><p>用不来怎么办？ <a href="https://www.xinz.fun/archives/Napcat" target="_blank" rel="noreferrer">点我前往不知名的友人提供的教程</a></p><p><a href="https://github.com/NapNeko/NapCat-Docker" target="_blank" rel="noreferrer">使用 NapCat-Docker</a></p></details><details class="details custom-block"><summary>Termux 一键脚本</summary><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> napcat.termux.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://nclatest.znin.net/NapNeko/NapCat-Installer/main/script/install.termux.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> napcat.termux.sh</span></span></code></pre></div></details><details class="details custom-block"><summary>在 Railway 上部署</summary><p><a href="https://railway.app/template/aRUNRZ?referralCode=Ns2Kracy" target="_blank" rel="noreferrer"><img src="https://railway.app/button.svg" alt="Deploy on Railway"></a></p></details><details class="details custom-block"><summary>在 1Panel 通过插件部署</summary><p><a href="https://github.com/Fahaxikiii/napcat-1panel" target="_blank" rel="noreferrer">前往插件仓库</a></p><p>通过1Panel插件 简单部署NapCatQQ 注意此方案并非官方维护</p></details><h4 id="手动-半自动撸猫" tabindex="-1">手动/半自动撸猫 <a class="header-anchor" href="#手动-半自动撸猫" aria-label="Permalink to &quot;手动/半自动撸猫&quot;">​</a></h4><h3 id="方法3-only-gui" tabindex="-1">方法3: Only GUI <a class="header-anchor" href="#方法3-only-gui" aria-label="Permalink to &quot;方法3: Only GUI&quot;">​</a></h3><h2 id="使用之后" tabindex="-1">使用之后 <a class="header-anchor" href="#使用之后" aria-label="Permalink to &quot;使用之后&quot;">​</a></h2><p>恭喜你，如果看到这里，你已经成功启动了它，可以尝试阅读下面的进阶说明！</p><p><a href="./config/basic">如何进行 NapCat 的基础设置</a></p><p><a href="./faq">如何配置 NapCat 的语音发送</a> 参考 <code>语音、视频发送失败</code> 发生失败条目</p><p><a href="./faq">遇到 NapCat 崩溃问题如何解决</a></p>',27)]))}const m=e(l,[["render",n]]);export{u as __pageData,m as default};
